return {{date="2026-01-20",author="CrazySpottedDove",message="更新完五代主线。部分功能可能尚未实现有点奇怪，不过应该不影响游玩。代码存在冲突，如有机制与原版有差异，请通知作者。感谢MC123很久之前提供的美术素材资源与索引，感谢FL作者提供的代码支持。"},{date="2026-01-20",author="CrazySpottedDove",message="为作者的话设置强制的最小阅读时间"},{date="2026-01-20",author="CrazySpottedDove",message="限制了五代塔和五代英雄需要通过五代关卡解锁，已有存档的防御塔不受影响，英雄需自行解锁。移植了维斯帕。"},{date="2026-01-21",author="CrazySpottedDove",message="细化更新器日志输出"},{date="2026-01-21",author="CrazySpottedDove",message="修复五代第一关出怪间隔异常问题"},{date="2026-01-21",author="CrazySpottedDove",message="允许五代第一关使用技能"},{date="2026-01-21",author="CrazySpottedDove",message="使五代奥法能吃到2号科技线的法塔科技加成"},{date="2026-01-21",author="CrazySpottedDove",message="修复犀牛的冲撞导致的一系列bug"},{date="2026-01-21",author="CrazySpottedDove",message="使维斯帕的逃脱触发与生命值无关"},{date="2026-01-21",author="CrazySpottedDove",message="略微提升蕾琳的普攻伤害"},{date="2026-01-21",author="CrazySpottedDove",message="提升五代第六关的初始经济100元"},{date="2026-01-21",author="CrazySpottedDove",message="回调五代第六关经济，并调整五代敌人的数值至正常水平"},{date="2026-01-21",author="CrazySpottedDove",message="再次修正五代部分敌人的生命值异常"},{date="2026-01-21",author="CrazySpottedDove",message="修正格里姆森的恢复数值；使维斯帕的远程射击状态dps高于近战状态（提升远程射击状态dps）"},{date="2026-01-21",author="CrazySpottedDove",message="修复铁皮代码导致的维斯帕近战技能释放顺序不当问题；修复维斯帕的射击范围显示不正确的问题"},{date="2026-01-21",author="CrazySpottedDove",message="修复维斯帕远近箭矢伤害异常问题"},{date="2026-01-21",author="CrazySpottedDove",message="修复骇人刃爪移速不正常问题；修复梦魇的受锁问题"},{date="2026-01-21",author="CrazySpottedDove",message="修复点击五代迪纳斯时会蓝屏的问题"},{date="2026-01-21",author="CrazySpottedDove",message="减少维斯帕闪避后摇；修复大眼换塔导致塔阻塞的问题"},{date="2026-01-21",author="CrazySpottedDove",message="优化维斯帕闪避后的强化攻击索敌"},{date="2026-01-21",author="CrazySpottedDove",message="fmt"}}
